1	// ---- Domain types ----
2	type Item = {
3	  type: string;
4	  material?: string;
5	  enchantment?: number;
6	  cursed?: boolean;
7	};
8	
9	type QuoteStep = { op: "quote"; items: Item[] };
10	type Scenario = {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	};
14	type QuoteResult = { premium: number };
15	type ScenarioResult = { results: QuoteResult[] };
16	
17	// ---- Pricing constants ----
18	const PROCESSING_FEE = 5;
19	const INITIAL_ASSESSMENT_SURCHARGE_RATE = 0.1;
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const BLOCK_SIZE = 3;
35	const BLOCK_OF_THREE_PREMIUM = 60;
36	
37	// ---- Base-premium calculation (per type group) ----
38	const priceSameTypeGroup = (type: string, count: number): number =>
39	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
40	    ? BLOCK_OF_THREE_PREMIUM
41	    : count * BASE_PREMIUM[type];
42	
43	const countByType = (items: Item[]): Map<string, number> => {
44	  const counts = new Map<string, number>();
45	  for (const item of items) {
46	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
47	  }
48	  return counts;
49	};
50	
51	const sumBasePremiums = (items: Item[]): number =>
52	  Array.from(countByType(items)).reduce(
53	    (total, [type, count]) => total + priceSameTypeGroup(type, count),
54	    0,
55	  );
56	
57	// ---- Per-item surcharges ----
58	const itemSurcharge = (item: Item): number => {
59	  const base = BASE_PREMIUM[item.type];
60	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
61	  const highEnch =
62	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
63	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
64	      : 0;
65	  return curse + highEnch;
66	};
67	
68	const sumItemSurcharges = (items: Item[]): number =>
69	  items.reduce((total, item) => total + itemSurcharge(item), 0);
70	
71	// ---- Quote assembly ----
72	const quotePremium = (items: Item[]): number => {
73	  const policyBase = sumBasePremiums(items);
74	  const itemSurcharges = sumItemSurcharges(items);
75	  const initialAssessment = policyBase * INITIAL_ASSESSMENT_SURCHARGE_RATE;
76	  return Math.ceil(policyBase + itemSurcharges + initialAssessment) + PROCESSING_FEE;
77	};
78	
79	export const runScenario = (input: Scenario): ScenarioResult => {
80	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
81	  return { results };
82	};
